{
var seed = GetInt(parameters, "seed", context.Seed);
var density = GetFloat(parameters, "density", 0.7f);
var grassLength = GetFloat(parameters, "grassLength", 0.5f);
var grassWidth = GetFloat(parameters, "grassWidth", 0.4f);
var windAngle = GetFloat(parameters, "windAngle", 0f);
var windStrength = GetFloat(parameters, "windStrength", 0.3f);
var grassColor1 = GetColor(parameters, "grassColor1", Color.FromRgb(60, 140, 40));
var grassColor2 = GetColor(parameters, "grassColor2", Color.FromRgb(100, 180, 60));
var soilColor = GetColor(parameters, "soilColor", Color.FromRgb(120, 90, 60));
var colorVar = GetFloat(parameters, "colorVariation", 0.2f);
var clumping = GetFloat(parameters, "clumping", 0.5f);
var detail = GetFloat(parameters, "detail", 0.3f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var g1R = grassColor1.R / 255f; var g1G = grassColor1.G / 255f; var g1B = grassColor1.B / 255f;
var g2R = grassColor2.R / 255f; var g2G = grassColor2.G / 255f; var g2B = grassColor2.B / 255f;
var sR = soilColor.R / 255f; var sG = soilColor.G / 255f; var sB = soilColor.B / 255f;

var windRad = windAngle * MathF.PI / 180f;
var cosWind = MathF.Cos(windRad);
var sinWind = MathF.Sin(windRad);

// Number of grass blades (proportional to density and tile size)
var bladeCount = (int)(density * density * size * 0.8f);
bladeCount = Math.Max(8, Math.Min(bladeCount, 500));

// Pre-generate blade positions and properties
var blades = new (float x, float y, float len, float width, float bend, float hueShift, float brightness)[bladeCount];
for (var i = 0; i < bladeCount; i++)
{
    var bx = HashToUnit(i * 7, seed, 111);
    var by = HashToUnit(i * 13, seed * 3, 222);
    var bl = 0.3f + HashToUnit(i * 17, seed * 5, 333) * 0.7f; // 0.3-1.0
    var bw = 0.2f + HashToUnit(i * 23, seed * 7, 444) * 0.8f; // 0.2-1.0
    var bb = (HashToUnit(i * 29, seed * 11, 555) - 0.5f) * 2f; // -1..1
    var bh = (HashToUnit(i * 31, seed * 13, 666) - 0.5f) * 2f; // -1..1
    blades[i] = (bx, by, bl, bw, bb, bh, 0f);
}

// Pre-compute clump centers
var clumpCount = Math.Max(1, (int)(density * size * 0.15f));
var clumps = new (float x, float y, float radius)[clumpCount];
for (var i = 0; i < clumpCount; i++)
{
    clumps[i] = (
        HashToUnit(i * 37, seed * 17, 777),
        HashToUnit(i * 41, seed * 19, 888),
        0.1f + HashToUnit(i * 43, seed * 23, 999) * 0.2f
    );
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // --- Soil base ---
    var soilNoise = TileableFractalNoise(
        u * 3f, v * 3f,
        3, 2, 0.5f, 2f, seed + 50);
    var soilBright = (soilNoise - 0.5f) * 0.15f;
    var baseR = Math.Clamp(sR + soilBright, 0f, 1f);
    var baseG = Math.Clamp(sG + soilBright * 0.8f, 0f, 1f);
    var baseB = Math.Clamp(sB + soilBright * 0.6f, 0f, 1f);

    // --- Blade rendering ---
    var maxBladeContrib = 0f;
    var bladeColorR = 0f;
    var bladeColorG = 0f;
    var bladeColorB = 0f;

    foreach (var (bx, by, bl, bw, bb, bh, _) in blades)
    {
        // Compute distance to this blade in wrapped UV space
        var dx = u - bx;
        var dy = v - by;
        if (dx > 0.5f) dx -= 1f; else if (dx < -0.5f) dx += 1f;
        if (dy > 0.5f) dy -= 1f; else if (dy < -0.5f) dy += 1f;

        // Wind bends the blade tip in wind direction
        var windBend = windStrength * bl * 0.15f;
        var tipOffsetX = cosWind * windBend;
        var tipOffsetY = sinWind * windBend;

        // Blade grows upward from base (local Y = 0 at base, 1 at tip)
        // The blade is a thin curved shape
        var bladeLen = grassLength * (0.3f + bl * 0.7f);
        var bladeW = grassWidth * (0.2f + bw * 0.8f) * 0.03f;

        // Project pixel onto the blade axis
        // Blade direction: from base (bx,by) upward, bent by wind
        var axisX = tipOffsetX;
        var axisY = -bladeLen + tipOffsetY; // negative Y = upward in screen space

        // For simplicity, approximate blade as a thin tapered line
        // Distance from pixel to blade center line
        // Transform pixel to blade-local space
        var toPixelX = dx;
        var toPixelY = dy;

        // Blade normalized direction
        var bladeDirLen = MathF.Sqrt(axisX * axisX + axisY * axisY);
        if (bladeDirLen < 0.001f) continue;

        // Project onto blade axis
        var dot = (toPixelX * axisX + toPixelY * axisY) / bladeDirLen;
        var alongBlade = dot / bladeDirLen; // 0 at base, 1 at tip

        if (alongBlade < -0.1f || alongBlade > 1.1f) continue;

        // Perpendicular distance from blade center line
        var perpX = toPixelX - (axisX / bladeDirLen) * dot;
        var perpY = toPixelY - (axisY / bladeDirLen) * dot;
        var perpDist = MathF.Sqrt(perpX * perpX + perpY * perpY);

        // Blade tapers toward tip
        var taper = 1f - alongBlade * 0.6f;

        // Blade width (wider at base, narrow at tip)
        var halfWidth = bladeW * taper * 0.5f;

        if (perpDist > halfWidth) continue;

        // Distance from blade center determines opacity
        var bladeAlpha = 1f - (perpDist / halfWidth);
        bladeAlpha = bladeAlpha * bladeAlpha * (3f - 2f * bladeAlpha); // smoothstep

        // Height-based color: tip is lighter green, base is darker
        var heightBlend = alongBlade;
        var bladeR = Lerp(g1R, g2R, heightBlend);
        var bladeG = Lerp(g1G, g2G, heightBlend);
        var bladeB = Lerp(g1B, g2B, heightBlend);

        // Per-blade color variation
        var hShift = bh * colorVar;
        bladeR = Math.Clamp(bladeR + hShift, 0f, 1f);
        bladeG = Math.Clamp(bladeG + hShift * 0.7f, 0f, 1f);
        bladeB = Math.Clamp(bladeB + hShift * 0.4f, 0f, 1f);

        // Contrast with soil is stronger near base
        var soilBlend = 1f - alongBlade * 0.3f;
        bladeAlpha *= soilBlend;

        // Clustering: blades in clumps are more visible
        if (clumping > 0f)
        {
            // Check if this blade is near a clump center
            foreach (var (cx, cy, _) in clumps)
            {
                var cdx = bx - cx;
                var cdy = by - cy;
                if (cdx > 0.5f) cdx -= 1f; else if (cdx < -0.5f) cdx += 1f;
                if (cdy > 0.5f) cdy -= 1f; else if (cdy < -0.5f) cdy += 1f;
                var cDist = MathF.Sqrt(cdx * cdx + cdy * cdy);
                if (cDist < 0.15f)
                {
                    bladeAlpha *= 1f + clumping * 0.5f;
                    break;
                }
            }
        }

        bladeAlpha = Math.Clamp(bladeAlpha, 0f, 1f);

        if (bladeAlpha > maxBladeContrib)
        {
            maxBladeContrib = bladeAlpha;
            bladeColorR = bladeR;
            bladeColorG = bladeG;
            bladeColorB = bladeB;
        }
    }

    // --- Detail noise for fine grass texture ---
    if (detail > 0f)
    {
        var detailNoise = TileableFractalNoise(
            u * 8f, v * 8f,
            8, 2, 0.5f, 2.5f, seed + 600);
        var detailVal = (detailNoise - 0.5f) * detail * 0.1f;
        baseR = Math.Clamp(baseR + detailVal, 0f, 1f);
        baseG = Math.Clamp(baseG + detailVal * 0.7f, 0f, 1f);
        baseB = Math.Clamp(baseB + detailVal * 0.5f, 0f, 1f);
    }

    // --- Compose: blend grass over soil ---
    float finalR, finalG, finalB;
    if (maxBladeContrib > 0.01f)
    {
        finalR = Lerp(baseR, bladeColorR, maxBladeContrib);
        finalG = Lerp(baseG, bladeColorG, maxBladeContrib);
        finalB = Lerp(baseB, bladeColorB, maxBladeContrib);
    }
    else
    {
        finalR = baseR;
        finalG = baseG;
        finalB = baseB;
    }

    // Brightness and contrast
    finalR = Math.Clamp(finalR + brightness, 0f, 1f);
    finalG = Math.Clamp(finalG + brightness, 0f, 1f);
    finalB = Math.Clamp(finalB + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        finalR = (finalR - 0.5f) * factor + 0.5f;
        finalG = (finalG - 0.5f) * factor + 0.5f;
        finalB = (finalB - 0.5f) * factor + 0.5f;
    }

    if (invert) { finalR = 1f - finalR; finalG = 1f - finalG; finalB = 1f - finalB; }

    buffer.SetPixel(x, y, Math.Clamp(finalR, 0f, 1f), Math.Clamp(finalG, 0f, 1f), Math.Clamp(finalB, 0f, 1f), 1f);
});

return buffer;
}
